                            display: 'flex', 
                            alignItems: 'center', 
                            gap: adminSidebarCollapsed ? '0' : '12px',
                            justifyContent: adminSidebarCollapsed ? 'center' : 'flex-start',
                            marginBottom: adminSidebarCollapsed ? '8px' : '12px',
                            flexWrap: adminSidebarCollapsed ? 'wrap' : 'nowrap'
