                                        fontSize: '14px', 
                                        fontWeight: 700,
                                        marginBottom: '2px',
                                        textShadow: '0 1px 2px rgba(0,0,0,0.3)'
                                    }}>
                                        {user?.firstName && user?.lastName 
                                            ? `${user.firstName} ${user.lastName}` 
