                                    fontSize: '16px',
                                    backdropFilter: 'blur(15px)',
                                    boxShadow: '0 8px 20px rgba(0,0,0,0.2), inset 0 1px 0 rgba(255,255,255,0.2)',
                                    position: 'relative',
                                    overflow: 'hidden',
                                    padding: adminSidebarCollapsed ? '0' : '8px 12px'
                                }}
                                onClick={() => setAdminSidebarCollapsed(!adminSidebarCollapsed)}
